#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    if (n == 1) {
        cout << 0 << endl;
    } else {
        if (nums[0] >= nums[1]) {
            cout << 0 << endl;
        } else if (nums[n - 1] >= nums[n - 2]) {
            cout << n - 1 << endl;
        } else {
            int left = 0, right = n - 1;
            while (left <= right) {
                int mid = left + (right - left) / 2;
                if ((mid == 0 || nums[mid] >= nums[mid - 1]) && (mid == n - 1 || nums[mid] >= nums[mid + 1])) {
                    cout << mid << endl;
                    break;
                } else if (mid > 0 && nums[mid - 1] > nums[mid]) {
                    right = mid - 1;
                } else {
                    left = mid + 1;
                }
            }
        }
    }
    return 0;
}
